// Variant 2: Force backward UTF-8 scanning (njs_utf8_prev) by searching for a multi-byte emoji after padding (aim: probe prev path)
function placeholder(){}
function main() {
  var fill = String.fromCharCode(-950135168).trimEnd(String);
  var len = 1024 >>> "multiline";
  // emoji via surrogate pair (multi-byte UTF-8 when encoded)
  var emoji = String.fromCharCode(0xD83D, 0xDE00); // 😀
  var base = String.fromCharCode(788580.490736339);
  // pad the base then append emoji so lastIndexOf has to scan backwards through padded region
  var s = base.padEnd(len, fill) + emoji + "Z";
  var idx = s.lastIndexOf(emoji);
}
main();
EOF

